import xml.etree.ElementTree as ET

def validate_xml(file_path):
    tree = ET.parse(file_path)
    root = tree.getroot()
    
    # Validate that the XML document has a valid root element
    if root.tag != 'document':
        raise ValueError('Invalid root element')
    
    # Validate that the XML document has at least one <item> element
    items = root.findall('.//item')
    if len(items) == 0:
        raise ValueError('No items found')
    
    # Validate that each item has a valid title and description
    for item in items:
        title = item.find('title')
        description = item.find('description')
        if title is None or description is None:
            raise ValueError('Invalid item data')
        
    return True